import { useState, useEffect } from "react";
import { Mail, Phone, MapPin, Send } from "lucide-react";
import "../../css/components/Contact/Contact.css";
import { submitContact } from "../../api/contactapi";
import { useAuth } from "../../context/AuthContext";

function Contact(){
  const { user, isAuthenticated } = useAuth();

  const [form,setForm]=useState({
    name: user?.full_name || user?.username || "",
    email: user?.email || "",
    phone_number: user?.phone_number || "",
    subject:"",
    message:""
  });

  useEffect(() => {
    if (user) {
      setForm(prev => ({
        ...prev,
        name: user.full_name || user.username || "",
        email: user.email || "",
        phone_number: user.phone_number || ""
      }));
    }
  }, [user]);

  const [loading, setLoading] = useState(false);

  const handleChange=(e)=>{
    setForm({...form,[e.target.name]:e.target.value})
  }

const handleSubmit= async (e)=>{
e.preventDefault();
setLoading(true);

try {
await submitContact(form);
alert("Message Sent Successfully");
setForm({
name:"",
email:"",
phone_number:"",
subject:"",
message:""
});
} catch (err) {
alert("Failed to send message");
}
setLoading(false);
}

return(

<div className="contact-container">
    <div className="contact-background-shapes">
        <div className="c-shape c-shape-1"></div>
        <div className="c-shape c-shape-2"></div>
    </div>

    <div className="contact-wrapper">
        {/* LEFT SIDE CONTACT INFO */}
        <div className="contact-info animate-slide-left">
            <h2 className="section-title">Get In Touch</h2>
            <p className="section-desc">Have questions or want to collaborate with our talk show? Reach out to us.</p>

            <div className="info-cards-container">
                <div className="info-card-dynamic">
                    <div className="icon-box"><Mail size={24}/></div>
                    <div className="info-content">
                        <label>Email Us</label>
                        <span>talkshow@gmail.com</span>
                    </div>
                </div>

                <div className="info-card-dynamic">
                    <div className="icon-box"><Phone size={24}/></div>
                    <div className="info-content">
                        <label>Call Us</label>
                        <span>+91 9876543210</span>
                    </div>
                </div>

                <div className="info-card-dynamic">
                    <div className="icon-box"><MapPin size={24}/></div>
                    <div className="info-content">
                        <label>Location</label>
                        <span>Hyderabad, India</span>
                    </div>
                </div>
            </div>
        </div>

        {/* RIGHT SIDE FORM */}
        <div className="contact-form-wrapper animate-slide-right">
            <div className="contact-form-glass">
                <h2>Send Message</h2>
                <form onSubmit={handleSubmit} className="modern-form">
                    <div className="input-field">
                        <input
                            type="text"
                            name="name"
                            placeholder="Your Name"
                            value={form.name}
                            onChange={handleChange}
                            required
                        />
                        <div className="input-focus-line"></div>
                    </div>

                    <div className="input-field">
                        <input
                            type="email"
                            name="email"
                            placeholder="Your Email"
                            value={form.email}
                            onChange={handleChange}
                            readOnly={isAuthenticated}
                            required
                        />
                        <div className="input-focus-line"></div>
                    </div>

                    <div className="input-field">
                        <input
                            type="text"
                            name="phone_number"
                            placeholder="Phone Number"
                            value={form.phone_number}
                            onChange={handleChange}
                            required
                        />
                        <div className="input-focus-line"></div>
                    </div>

                    <div className="input-field">
                        <input
                            type="text"
                            name="subject"
                            placeholder="Subject"
                            value={form.subject}
                            onChange={handleChange}
                            required
                        />
                        <div className="input-focus-line"></div>
                    </div>

                    <div className="input-field">
                        <textarea
                            name="message"
                            placeholder="Your Message"
                            value={form.message}
                            onChange={handleChange}
                            required
                        />
                        <div className="input-focus-line"></div>
                    </div>

                    <button type="submit" className="glow-submit-btn" disabled={loading}>
                        <Send size={18}/> <span>{loading ? "Sending..." : "Send Message"}</span>
                    </button>
                </form>
            </div>
        </div>
    </div>
</div>

)

}

export default Contact;

import { useState, useEffect, useRef } from "react";
import ReactDOM from "react-dom";
import { useNavigate } from "react-router-dom";
import { FiX, FiPlay } from "react-icons/fi";
import { getEpisodes } from "../../api/guestapi";
import { getMediaBase } from "../../api/api";
import { useAuth } from "../../context/AuthContext";
import AuthGuard from "../Common/AuthGuard";
import "../../css/components/episodes/EpisodesGrid.css";
import "../../css/components/episodes/EpisodeOverlay.css";

function EpisodesGrid({ search, episodes }) {
  const [selectedEpisode, setSelectedEpisode] = useState(null);
  const [showOverlay, setShowOverlay] = useState(false);
  const [showGuard, setShowGuard] = useState(false);
  const navigate = useNavigate();
  const { isAuthenticated } = useAuth();
  const videoRef = useRef(null);

  const filteredEpisodes = episodes.filter(episode => 
    episode.name.toLowerCase().includes((search || "").toLowerCase()) ||
    (episode.bio && episode.bio.toLowerCase().includes((search || "").toLowerCase()))
  );

  const handleEpisodeClick = (episode) => {
    setSelectedEpisode(episode);
    setShowOverlay(true);
  };

  const closeOverlay = () => {
    setShowOverlay(false);
    setSelectedEpisode(null);
  };

  const navigateToFull = () => {
    if (!isAuthenticated) {
        setShowGuard(true);
        return;
    }
    navigate(`/play/ep_${selectedEpisode.id}`);
  };

  const getFullUrl = (path) => {
    if (!path) return "";
    if (path.startsWith("http")) return path;
    return getMediaBase() + path;
  };

  return (
    <div className="episodes-grid">
      {filteredEpisodes.map((episode, index) => (
        <div 
          key={episode.id} 
          className="episode-card animate-card-in" 
          onClick={() => handleEpisodeClick(episode)}
          style={{ "--index": index }}
        >
          <div className="episode-image">
            <img src={episode.thumbnail || episode.guest_image} alt={episode.name} />
            <div className="episode-poster-overlay">
               <div className="episode-content">
                  <span className="episode-date">
                    {new Date(episode.upload_datetime).toDateString()}
                  </span>
                  <h3 className="episode-name">{episode.name}</h3>
                  <div className="card-spacer"></div>
                  <p className="episode-bio">{episode.bio?.substring(0, 80)}...</p>
               </div>
               <div className="poster-play-btn">
                  <FiPlay />
               </div>
            </div>
          </div>
        </div>
      ))}

      {showOverlay && selectedEpisode && ReactDOM.createPortal(
        <div className="episode-overlay" onClick={closeOverlay}>
          <div className="overlay-vignette"></div>

          <div className="cinematic-container" onClick={(e) => e.stopPropagation()}>
            <button className="close-overlay-cinematic" onClick={closeOverlay}>
              <FiX />
            </button>

            <div className="main-stage">
              <div className="promo-player-wrapper">
                <video 
                  ref={videoRef}
                  src={getFullUrl(selectedEpisode.promo_video)} 
                  autoPlay 
                  controls 
                  className="promo-video-main"
                />
              </div>

              <div className="side-metadata">
                <div className="meta-glass-card">
                  <span className="meta-label">EXCLUSIVE PROMO</span>
                  <h2 className="meta-title">{selectedEpisode.name}</h2>
                  <div className="meta-divider"></div>

                  <div className="meta-details">
                    <div className="detail-item">
                      <label>PREMIERED</label>
                      <span>{new Date(selectedEpisode.upload_datetime).toLocaleDateString(undefined, { month: 'long', day: 'numeric', year: 'numeric' })}</span>
                    </div>
                    <div className="detail-item">
                      <label>EPISODE</label>
                      <span>VOL. 0{selectedEpisode.id}</span>
                    </div>
                  </div>

                  <p className="meta-desc">
                    {selectedEpisode.bio || "No description available for this episode."}
                  </p>

                  <button className="cinematic-watch-btn" onClick={navigateToFull}>
                    <FiPlay className="btn-icon" />
                    <span>WATCH FULL VERSION</span>
                  </button>
                </div>
              </div>
            </div>

            <div className="cinematic-bottom-bar">
               <div className="scroll-hint">
                  <div className="mouse"></div>
                  <span>CINEMATIC PREVIEW MODE</span>
               </div>
            </div>
          </div>
        </div>,
        document.body
      )}

      {showGuard && (
        <AuthGuard 
          onClose={() => setShowGuard(false)} 
          message="Enjoy the premier experience! Please login or register to watch the full performance and exclusive uncut footage." 
        />
      )}
    </div>
  );
}

export default EpisodesGrid;

import React, { useState, useEffect, useRef } from "react";
import { FiSearch } from "react-icons/fi";
import { Link } from "react-router-dom";
import { searchEpisodes } from "../../api/talentstoriesapi";
import { getMediaBase } from "../../api/api";
import { useAuth } from "../../context/AuthContext";
import AuthGuard from "../Common/AuthGuard";
import { useNavigate } from "react-router-dom";
import "../../css/components/episodes/EpisodesHeader.css";

function EpisodesHeader({ search, setSearch, episodes }) {
  const navigate = useNavigate();
  const { isAuthenticated } = useAuth();
  const [searchQuery, setSearchQuery] = useState(search || "");
  const [searchResults, setSearchResults] = useState([]);
  const [isSearching, setIsSearching] = useState(false);
  const [showSearchResults, setShowSearchResults] = useState(false);
  const [showGuard, setShowGuard] = useState(false);
  const searchRef = useRef(null);

  useEffect(() => {
    const timer = setTimeout(async () => {
      if (searchQuery.length >= 2) {
        setIsSearching(true);
        try {
          const data = await searchEpisodes(searchQuery);
          setSearchResults(data);
          setShowSearchResults(true);
        } catch (error) {
          console.error("Search error:", error);
        } finally {
          setIsSearching(false);
        }
      } else {
        setSearchResults([]);
        setShowSearchResults(false);
      }
    }, 400);

    return () => clearTimeout(timer);
  }, [searchQuery]);

  const handleResultClick = (result) => {
    if (!isAuthenticated) {
      setShowGuard(true);
      return;
    }
    setShowSearchResults(false);
    setSearchQuery("");
    setSearch(result.name);
    navigate(`/play/ep_${result.id}`);
  };


  useEffect(() => {
    const handleClickOutside = (event) => {
      if (searchRef.current && !searchRef.current.contains(event.target)) {
        setShowSearchResults(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const getImageUrl = (path) => {
    if (!path) return "/default-thumbnail.png";
    if (path.startsWith("http")) return path;
    return getMediaBase() + path;
  };

  return (
    <div className="episodes_head">
      <div className="episodes_container">
        <span className="episodes_tag">EXCLUSIVE CONTENT</span>
        <h1 className="episodes_title">
          Talk Show <span>Episodes</span>
        </h1>
        <p className="episodes_desc">
          Watch inspiring conversations and powerful stories from our incredible guests.
        </p>

        <div className="episodes_search" ref={searchRef}>
          <FiSearch className="search_icon" />
          <input 
            type="text" 
            placeholder="Search for episodes or guests..." 
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            onFocus={() => searchQuery.length >= 2 && setShowSearchResults(true)}
          />
          {isSearching && <div className="search-loader"></div>}

          {showSearchResults && (
            <div className="episodes-search-results">
              {searchResults.length > 0 ? (
                searchResults.map(result => (
                  <div 
                    key={result.id} 
                    className="episode-result-item"
                    onClick={() => handleResultClick(result)}
                  >
                    <div className="result-thumb">
                      <img src={getImageUrl(result.thumbnail)} alt={result.name} />
                    </div>
                    <div className="result-info">
                      <div className="result-top">
                        <span className="result-name">{result.name}</span>
                        {result.is_new && <span className="result-id">NEW</span>}
                      </div>
                      <div className="result-meta">
                        <span className="result-guest">with {result.guest_name}</span>
                      </div>
                      {result.bio && (
                        <p className="result-bio-preview">{result.bio.substring(0, 100)}...</p>
                      )}
                    </div>
                  </div>
                ))
              ) : searchQuery.length >= 2 && !isSearching ? (
                <div className="search-no-results">
                   <FiSearch />
                   <div className="no-res-content">
                      <h4>No episodes found for "{searchQuery}"</h4>
                      <p>Try searching for guest names or different keywords.</p>
                   </div>
                </div>
              ) : null}
            </div>
          )}
        </div>
      </div>

      {showGuard && (
        <AuthGuard 
          onClose={() => setShowGuard(false)} 
          message="Experience the full performance! Please login or register to watch complete episodes and exclusive uncut footage." 
        />
      )}
    </div>
  );
}

export default EpisodesHeader;

