import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import "../../css/components/Login/LoginRegister.css";

import {
  loginUser,
  sendOtpAPI,
  verifyOtpAPI,
  registerUser,
  googleLogin,
  getRoles,
} from "../../api/loginregisterapi";
import { useAuth } from "../../context/AuthContext";

function LoginRegister() {
  const navigate = useNavigate();
  const { login: contextLogin } = useAuth();

  const [isLogin, setIsLogin] = useState(true);

  const [otpSent, setOtpSent] = useState(false);
  const [otpVerified, setOtpVerified] = useState(false);
  const [regStep, setRegStep] = useState(1);

  const [timer, setTimer] = useState(0);

  const [otp, setOtp] = useState(["", "", "", "", "", ""]);

  const [message, setMessage] = useState("");
  const [msgType, setMsgType] = useState("");

  const [form, setForm] = useState({
    username: "",
    full_name: "",
    email: "",
    phone_number: "",
    password: "",
    confirm_password: "",
    profile: null,
    role: "",
    gender: "",
    bio: "",
  });

  const [roles, setRoles] = useState([]);

  useEffect(() => {
    getRoles().then(data => setRoles(data)).catch(() => {});
  }, []);

  useEffect(() => {
    if (timer > 0) {
      const t = setTimeout(() => {
        setTimer(timer - 1);
      }, 1000);

      return () => clearTimeout(t);
    }
  }, [timer]);

  useEffect(() => {
    if (isLogin) {
      setRegStep(1);
      setOtpSent(false);
      setOtpVerified(false);
      setOtp(["", "", "", "", "", ""]);
    }
  }, [isLogin]);

  useEffect(() => {
    if (message) {
      const t = setTimeout(() => {
        setMessage("");
      }, 4000);

      return () => clearTimeout(t);
    }
  }, [message]);

  function change(e) {
    if (e.target.name === "profile") {
      setForm({ ...form, profile: e.target.files[0] });
    } else if (e.target.name === "email" && !isLogin) {
      const email = e.target.value;
      const username = form.username || email.split("@")[0] || "";
      setForm({ ...form, email, username });
    } else {
      setForm({ ...form, [e.target.name]: e.target.value });
    }
  }

  function changeOtp(value, index) {
    if (!/^[0-9]?$/.test(value)) return;

    const newOtp = [...otp];
    newOtp[index] = value;
    setOtp(newOtp);

    if (value && index < 5) {
      const nextInput = document.querySelectorAll(".otpBoxes input")[index + 1];
      if (nextInput) nextInput.focus();
    }
  }

  function handleOtpKeyDown(e, index) {
    if (e.key === "Backspace" && !otp[index] && index > 0) {
      const prevInput = document.querySelectorAll(".otpBoxes input")[index - 1];
      if (prevInput) prevInput.focus();
    }
  }

  function sendOtp() {
    sendOtpAPI(form.email).then(function (data) {
      if (data.message) {
        setOtpSent(true);
        setRegStep(2);
        setTimer(40);
        setMessage("OTP sent to email");
        setMsgType("success");
      } else {
        setMessage(data.error);
        setMsgType("error");
      }
    });
  }

  function verifyOtp() {
    verifyOtpAPI(form.email, otp.join("")).then(function (data) {
      if (data.message) {
        setOtpVerified(true);
        setOtpSent(false);
        setRegStep(3);
        setMessage("OTP verified");
        setMsgType("success");
      } else {
        setMessage(data.error);
        setMsgType("error");
      }
    });
  }

  function register(e) {
    e.preventDefault();

    if (form.email && !otpVerified) {
      setMessage("Verify OTP first");
      setMsgType("error");
      return;
    }

    if (form.password !== form.confirm_password) {
      setMessage("Passwords not matching");
      setMsgType("error");

      return;
    }

    registerUser(form).then(function (data) {
      if (data.message) {
        setMessage("Account created successfully");
        setMsgType("success");

        setForm({
          username: "",
          full_name: "",
          email: "",
          phone_number: "",
          password: "",
          confirm_password: "",
          profile: null,
          role: "",
          gender: "",
          bio: "",
        });

        setOtp(["", "", "", "", "", ""]);

        setOtpSent(false);
        setOtpVerified(false);
        setRegStep(1);
        setTimer(0);

        setIsLogin(true);
      } else {
        setMessage(data.error);
        setMsgType("error");
      }
    });
  }

  function login(e) {
    e.preventDefault();

    const identifier = form.username || form.email;

    loginUser(identifier, form.password).then(function (data) {
      if (data.message) {
        setMessage("Login successful");
        setMsgType("success");
        contextLogin(data);
        setTimeout(() => navigate("/"), 1500);
      } else {
        setMessage(data.error);
        setMsgType("error");
      }
    });
  }

  return (
    <div className="auth">
      <div className="card">
        {message && <div className={`msg-box ${msgType}`}>{message}</div>}

        <div className="box">

          <div className={`form ${!isLogin ? "hide" : ""}`}>
            <h1>Welcome Back</h1>

            <p className="subtitle">Login to your account</p>

            <form onSubmit={login}>
              <input
                type="text"
                name="email"
                placeholder="Email or Username"
                onChange={change}
                required
              />

              <input
                type="password"
                name="password"
                placeholder="Password"
                onChange={change}
                required
              />

              <span
                className="forgot"
                onClick={() => navigate("/forgot-password")}
              >
                Forgot Password?
              </span>

              <button className="main-btn">Login</button>

              <div className="divider">
                <span>or</span>
              </div>

              <button
                type="button"
                className="google-btn"
                onClick={googleLogin}
              >
                <img
                  src="https://developers.google.com/identity/images/g-logo.png"
                  alt="google"
                />
                Login with Google
              </button>
            </form>
          </div>

          <div className={`form ${isLogin ? "hide" : ""}`}>
            <h1>
              {regStep === 1 ? "Create Account" : regStep === 2 ? "Verify Email" : "Final Details"}
            </h1>

            <p className="subtitle">
              {regStep === 1 
                ? "Join the TalkShow family" 
                : regStep === 2 
                  ? "Enter OTP to continue" 
                  : "Finish setting up your profile"}
            </p>

            <form onSubmit={register}>
              {regStep === 1 && (
                <div className="step-1 animate-in">
                  <div className="row">
                    <input
                      type="text"
                      name="full_name"
                      placeholder="Full Name"
                      onChange={change}
                      value={form.full_name}
                      required
                    />
                  </div>
                  <div className="row">
                    <select 
                      name="gender" 
                      onChange={change} 
                      value={form.gender} 
                      className="auth-select gender-select"
                      required
                    >
                      <option value="">Select Gender</option>
                      <option value="male">Male</option>
                      <option value="female">Female</option>
                      <option value="other">Other</option>
                    </select>
                  </div>
                  <input
                    type="email"
                    name="email"
                    placeholder="Email Address"
                    onChange={change}
                    value={form.email}
                    required
                  />
                  <button type="button" className="main-btn" onClick={sendOtp}>
                    Send OTP
                  </button>
                </div>
              )}

              {regStep === 2 && (
                <div className="step-2 animate-in">
                  <p className="subtitle">Enter the 6-digit code sent to {form.email}</p>
                  <div className="otpSection">
                    <div className="otpBoxes">
                      {otp.map((v, i) => (
                        <input
                          key={i}
                          maxLength="1"
                          value={v}
                          onChange={(e) => changeOtp(e.target.value, i)}
                          onKeyDown={(e) => handleOtpKeyDown(e, i)}
                        />
                      ))}
                    </div>

                    <button
                      type="button"
                      className="main-btn"
                      onClick={verifyOtp}
                    >
                      Verify OTP
                    </button>

                    <div className="timer-section">
                      {timer > 0 ? (
                        <span>Resend OTP in {timer}s</span>
                      ) : (
                        <span className="resend" onClick={sendOtp}>
                          Resend Code
                        </span>
                      )}
                    </div>
                  </div>
                  <button type="button" className="forgot back-btn" onClick={() => setRegStep(1)}>
                    Back to Edit Info
                  </button>
                </div>
              )}

              {regStep === 3 && (
                <div className="step-3 animate-in">
                  <div className="row">
                    <input
                      type="text"
                      name="username"
                      placeholder="Username"
                      onChange={change}
                      value={form.username}
                      required
                    />
                    <select 
                      name="role" 
                      onChange={change} 
                      value={form.role} 
                      className="auth-select role-select"
                    >
                      <option value="">Talent/Role (Optional)</option>
                      {roles.map(r => (
                        <option key={r.id} value={r.id}>{r.name}</option>
                      ))}
                    </select>
                  </div>

                  <input
                    type="text"
                    name="bio"
                    placeholder="Short Bio"
                    onChange={change}
                    value={form.bio}
                  />

                  <div className="row">
                    <input
                      type="password"
                      name="password"
                      placeholder="Password"
                      onChange={change}
                      required
                    />
                    <input
                      type="password"
                      name="confirm_password"
                      placeholder="Confirm Password"
                      onChange={change}
                      required
                    />
                  </div>

                  <div className="file-input-wrapper">
                    <label>Profile Picture</label>
                    <input type="file" name="profile" onChange={change} />
                  </div>

                  <button className="main-btn">Complete Registration</button>
                </div>
              )}
            </form>
          </div>
        </div>

        <div className="switch">
          {isLogin ? (
            <p>
              New here?
              <span onClick={() => setIsLogin(false)}>Create Account</span>
            </p>
          ) : (
            <p>
              Already have account?
              <span onClick={() => setIsLogin(true)}>Sign In</span>
            </p>
          )}
        </div>
      </div>
    </div>
  );
}

export default LoginRegister;

import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { FiX, FiUser, FiUserPlus, FiCheck } from "react-icons/fi";
import { getFollowers, getFollowing } from "../../api/profileapi";
import { toggleSubscribe } from "../../api/talentstoriesapi";
import { getMediaBase } from "../../api/api";
import { useAuth } from "../../context/AuthContext";

function FollowListModal({ userId, type, onClose }) {
  const navigate = useNavigate();
  const { user: currentUser } = useAuth();
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);

  const getImageUrl = (path) => {
    if (!path) return "/default-avatar.png";
    if (path.startsWith("http")) return path;
    return getMediaBase() + path;
  };

  useEffect(() => {
    const fetchData = type === "followers" ? getFollowers : getFollowing;
    fetchData(userId)
      .then(data => {
        setUsers(data);
        setLoading(false);
      })
      .catch(() => setLoading(false));
  }, [userId, type]);

  const handleUserClick = (targetId) => {
    onClose();
    navigate(`/user/${targetId}`);
  };

  return (
    <div className="neat-modal-overlay" onClick={onClose}>
      <div className="neat-modal-content" onClick={e => e.stopPropagation()}>
        <div className="neat-modal-header">
          <h3>{type === "followers" ? "Followers" : "Following"}</h3>
          <button className="close-modal-btn" onClick={onClose}>
            <FiX />
          </button>
        </div>

        <div className="neat-modal-body">
          {loading ? (
            <div className="modal-loading">Loading users...</div>
          ) : users.length > 0 ? (
            <div className="user-list-container">
              {users.map(u => (
                <div key={u.id} className="user-list-item" onClick={() => handleUserClick(u.id)}>
                  <div className="user-list-avatar">
                    <img src={getImageUrl(u.profile)} alt={u.username} />
                  </div>
                  <div className="user-list-info">
                    <h4>{u.full_name || u.username}</h4>
                    <span className="user-list-role">{u.role_name || "Member"}</span>
                  </div>
                  <div className="user-list-action">
                     <span className="view-profile-hint">View Profile</span>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="modal-empty-state">
              <FiUser />
              <p>No {type} found.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default FollowListModal;

import "../../css/components/Profile/GuestsHeader.css";
import { FiSearch } from "react-icons/fi";
import { useState, useEffect, useRef } from "react";
import { Link } from "react-router-dom";
import { searchGuests } from "../../api/talentstoriesapi";
import { getMediaBase } from "../../api/api";
import { useAuth } from "../../context/AuthContext";
import AuthGuard from "../Common/AuthGuard";
import { useNavigate } from "react-router-dom";

function GuestsHeader({ search, setSearch, guests }) {
  const navigate = useNavigate();
  const { isAuthenticated } = useAuth();
  const [searchQuery, setSearchQuery] = useState(search || "");
  const [searchResults, setSearchResults] = useState([]);
  const [isSearching, setIsSearching] = useState(false);
  const [showSearchResults, setShowSearchResults] = useState(false);
  const [showGuard, setShowGuard] = useState(false);
  const searchRef = useRef(null);

  useEffect(() => {
    const timer = setTimeout(async () => {
      if (searchQuery.length >= 2) {
        setIsSearching(true);
        try {
          const data = await searchGuests(searchQuery);
          setSearchResults(data);
          setShowSearchResults(true);
        } catch (error) {
          console.error("Search error:", error);
        } finally {
          setIsSearching(false);
        }
      } else {
        setSearchResults([]);
        setShowSearchResults(false);
      }
    }, 400);

    return () => clearTimeout(timer);
  }, [searchQuery]);

  const handleResultClick = (result) => {
    if (!isAuthenticated) {
      setShowGuard(true);
      return;
    }
    setShowSearchResults(false);
    setSearchQuery("");
    setSearch(result.name);
    navigate(`/guest/${result.id}`);
  };


  useEffect(() => {
    const handleClickOutside = (event) => {
      if (searchRef.current && !searchRef.current.contains(event.target)) {
        setShowSearchResults(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const getImageUrl = (path) => {
    if (!path) return "/default-avatar.png";
    if (path.startsWith("http")) return path;
    return getMediaBase() + path;
  };

  return (
    <section className="guests_head">
      <div className="guests_head_container">
        <span className="guests_tag">LEGENDS</span>
        <h1 className="guests_title">
          FEATURED <span>GUESTS</span>
        </h1>
        <p className="guests_desc">
          Meet the extraordinary minds and personalities who have graced our platform.
        </p>

        <div className="guests_search" ref={searchRef}>
          <FiSearch className="search_icon" />

          <input
            type="text"
            placeholder="Search guests by name, designation, or bio..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            onFocus={() => searchQuery.length >= 2 && setShowSearchResults(true)}
          />
          {isSearching && <div className="search-loader"></div>}

          {showSearchResults && (
            <div className="guests-search-results">
              {searchResults.length > 0 ? (
                searchResults.map(result => (
                  <div 
                    key={result.id} 
                    className="guest-result-item"
                    onClick={() => handleResultClick(result)}
                  >
                    <div className="result-avatar">
                      <img src={getImageUrl(result.profile)} alt={result.name} />
                    </div>
                    <div className="result-info">
                      <div className="result-top">
                        <span className="result-name">{result.name}</span>
                        {result.is_new && <span className="result-id">NEW</span>}
                      </div>
                      <div className="result-meta">
                        <span className="result-designation">{result.designation}</span>
                      </div>
                      {result.bio && (
                        <p className="result-bio-preview">{result.bio.substring(0, 100)}...</p>
                      )}
                    </div>
                  </div>
                ))
              ) : searchQuery.length >= 2 && !isSearching ? (
                <div className="search-no-results">
                   <FiSearch />
                   <div className="no-res-content">
                      <h4>No legends found for "{searchQuery}"</h4>
                      <p>Try searching for names, designations or areas of expertise.</p>
                   </div>
                </div>
              ) : null}
            </div>
          )}
        </div>
      </div>

      {showGuard && (
        <AuthGuard 
          onClose={() => setShowGuard(false)} 
          message="Unlock the wisdom of legends! Please login or register to explore full guest profiles." 
        />
      )}
    </section>
  );
}

export default GuestsHeader;

import React, { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { FiMapPin, FiPlay, FiArrowLeft, FiUserPlus, FiCheck } from "react-icons/fi";
import getTalentStories, { getTalentById, toggleSubscribe } from "../../api/talentstoriesapi";
import { useAuth } from "../../context/AuthContext";
import { getMediaBase } from "../../api/api";
import "../../css/components/Profile/TalentProfile.css";

function TalentProfile() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();
  const [talent, setTalent] = useState(null);
  const [relatedTalents, setRelatedTalents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [isFollowing, setIsFollowing] = useState(false);
  const [followLoading, setFollowLoading] = useState(false);

  useEffect(() => {
    setLoading(true);
    // Fetch current talent
    getTalentById(id)
      .then((data) => {
        setTalent(data);
        setIsFollowing(data.is_following);
        // Fetch all talents for related stories section
        return getTalentStories();
      })
      .then((allTalents) => {
        // Filter out the current talent from related
        const related = allTalents.filter((t) => t.id !== parseInt(id));
        setRelatedTalents(related.slice(0, 4)); // Show top 4 related
        setLoading(false);
      })
      .catch((err) => {
        console.error("Error fetching talent details:", err);
        setLoading(false);
      });
  }, [id]);

  if (loading) {
    return (
      <div className="loading-container">
        <p>Loading talent story...</p>
      </div>
    );
  }

  if (!talent) {
    return (
      <div className="talent-profile-page">
        <h2>Talent not found</h2>
        <button onClick={() => navigate("/talentstories")}>Go Back</button>
      </div>
    );
  }

  const handleRelatedClick = (relatedId) => {
    navigate(`/talent/${relatedId}`);
    window.scrollTo(0, 0);
  };

  const handlePlayVideo = (videoIdOrUrl) => {
    navigate(`/play/${id}`); 
  };

  const handleToggleFollow = () => {
    if (!user) {
      navigate("/login");
      return;
    }
    if (user.id === talent.user) return;

    setFollowLoading(true);
    toggleSubscribe(talent.user)
      .then((res) => {
        setIsFollowing(res.subscribed);
        setFollowLoading(false);
      })
      .catch((err) => {
        console.error("Error toggling follow:", err);
        setFollowLoading(false);
      });
  };

  const getFullUrl = (path) => {
    if (!path) return "";
    return path.startsWith("http") ? path : `${getMediaBase()}${path}`;
  };

  return (
    <div className="talent-profile-page">
      <button className="global-back-btn" onClick={() => navigate("/talentstories")}>
        <FiArrowLeft /> Back to Stories
      </button>
      <div className="talent-profile-container">
        <div className="talent-profile-left">
          <img src={getFullUrl(talent.thumbnail)} alt={talent.name} />
        </div>

        <div className="talent-profile-right">
          <div className="talent-header-row">
            <div>
              <h4>{talent.talent}</h4>
              <h1>{talent.name}</h1>
            </div>
            {(!user || user.id !== talent.user) && (
              <button 
                className={`follow-btn-premium ${isFollowing ? 'following' : 'not-following'}`} 
                onClick={handleToggleFollow}
                disabled={followLoading}
              >
                {isFollowing ? <><FiCheck /> Following</> : <><FiUserPlus /> Follow</>}
              </button>
            )}
          </div>

          <div className="talent-stats-row">
            <div className="stat-pill">
              <span className="stat-value">{talent.followers_count || 0}</span>
              <span className="stat-label">Followers</span>
            </div>
            <div className="stat-pill">
              <span className="stat-value">{talent.following_count || 0}</span>
              <span className="stat-label">Following</span>
            </div>
            <div className="stat-pill">
              <span className="stat-value">{talent.uploaded_count || 0}</span>
              <span className="stat-label">Uploaded</span>
            </div>
          </div>

          <div className="talent-location">
            <FiMapPin /> {talent.state}, {talent.country}
          </div>

          <div className="talent-quotation">
            "{talent.quotation}"
          </div>

          {talent.user_bio && (
            <div className="talent-bio-short">
              <h3>Professional Bio</h3>
              <p>{talent.user_bio}</p>
            </div>
          )}

          <div className="talent-story">
            <h3>About the Journey</h3>
            <p>{talent.story_about_person}</p>
            <p>{talent.desc_of_talent}</p>
          </div>
        </div>
      </div>

      <div className="talent-video-section">
        <h2>Watch the Performance</h2>
        <div className="main-video-preview" onClick={() => handlePlayVideo(talent.id)}>
          <div className="video-thumbnail-container">
            <img 
              src={getFullUrl(talent.thumbnail)} 
              className="talent-main-video-poster" 
              alt="Video Poster"
            />
            <div className="play-overlay">
              <FiPlay className="play-btn-large" />
            </div>
          </div>
        </div>
      </div>

      <div className="related-talents-section">
        <h2>Discover More Stories</h2>
        <div className="talentstories_grid">
          {relatedTalents.map((related) => (
            <div 
              key={related.id} 
              className="talent_card"
              onClick={() => handleRelatedClick(related.id)}
            >
              <div className="talent_image">
                <img src={getFullUrl(related.thumbnail)} alt={related.name} />
                <div className="talent_overlay">
                  <div className="play_icon_center">
                    <FiPlay />
                  </div>
                  <span className="talent_category">{related.talent}</span>
                  <h3>{related.name}</h3>
                  <div className="talent_location">
                    <FiMapPin /> {related.state}, {related.country}
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

export default TalentProfile;

